import { useState, useMemo, useCallback } from "react";
import { api as http } from "../uiApiCompat";
import { usePoll } from "../hooks/usePoll";
import { useAppStore } from "../store/appStore";
import V2EmptyState from "../components/V2EmptyState";

/* ── helpers ─────────────────────────────────────────── */
const statusColor = (s) => {
  if (s === "DEPLOYED")   return "v2-green";
  if (s === "TRAINING")   return "v2-blue";
  if (s === "EVALUATING") return "v2-amber";
  if (s === "RETIRED")    return "v2-red";
  return "";
};
const fmtPct = (v) => v == null ? "--" : `${(v * 100).toFixed(1)}%`;
const tonePct = (v) => v == null ? "blue" : v > 0.8 ? "green" : v > 0.6 ? "amber" : "red";
const ago = (ts) => {
  if (!ts) return "--";
  const d = Date.now() - new Date(ts).getTime();
  if (d < 60000) return `${Math.floor(d / 1000)}s ago`;
  if (d < 3600000) return `${Math.floor(d / 60000)}m ago`;
  if (d < 86400000) return `${Math.floor(d / 3600000)}h ago`;
  return `${Math.floor(d / 86400000)}d ago`;
};

/* ── stat card ───────────────────────────────────────── */
function Stat({ label, value, tone = "blue", sub = "" }) {
  return (
    <div className="v2-card">
      <div className="v2-ct">{label}</div>
      <div className={`v2-cv v2-${tone}`}>{value}</div>
      {sub && <div className="v2-muted" style={{ marginTop: 8 }}>{sub}</div>}
    </div>
  );
}

/* ── main page ───────────────────────────────────────── */
export default function MLLab() {
  const { state, toast } = useAppStore();
  const [selectedModels, setSelectedModels] = useState([]);
  const [sortCol, setSortCol] = useState("accuracy");
  const [sortAsc, setSortAsc] = useState(false);

  /* poll model performance */
  const { data: mlData, loading } = usePoll(
    async () => { const r = await http.get("/ml/models/performance"); return r.data; },
    { intervalMs: 30000, enabled: !state.offlineMode }
  );

  /* poll strategies for catalogue integration */
  const fetchStrategies = useCallback(async () => {
    const r = await http.get("/strategies");
    return r.data;
  }, []);
  const { data: apiStrategies } = usePoll(fetchStrategies, { intervalMs: 30000, enabled: !state.offlineMode });

  const strategyCount = apiStrategies
    ? (Array.isArray(apiStrategies) ? apiStrategies.length
      : apiStrategies.total ?? (apiStrategies.strategies ?? []).length)
    : 0;

  /* derived data - normalise API fields */
  const rawModels = mlData?.models ?? mlData?.per_strategy ?? [];
  const models = rawModels.map(m => ({
    ...m,
    name: m.name ?? m.strategy ?? m.model_name ?? "unknown",
    status: m.status ?? (m.accuracy != null ? "DEPLOYED" : "UNKNOWN"),
    deployed_at: m.deployed_at ?? m.last_deployed ?? (m.trained_at
      ? new Date(m.trained_at * 1000).toISOString()
      : m.updated_at),
    updated_at: m.updated_at ?? (m.trained_at
      ? new Date(m.trained_at * 1000).toISOString()
      : null),
    sharpe: m.sharpe ?? m.auc_roc ?? null,
    predictions: m.predictions ?? m.count ?? m.train_samples ?? null,
  }));
  const features = mlData?.feature_importance ?? [];
  const trainingJobs = mlData?.training_queue ?? mlData?.training_jobs ?? [];
  const rawMetrics = mlData?.model_metrics ?? mlData?.metrics ?? null;
  /* normalise metric field names (API uses f1_score, pages expect f1) */
  const metrics = rawMetrics ? {
    ...rawMetrics,
    f1: rawMetrics.f1 ?? rawMetrics.f1_score ?? null,
    version: rawMetrics.version ?? mlData?.model_version ?? null,
    last_trained: rawMetrics.last_trained ?? (mlData?.last_trained
      ? new Date(mlData.last_trained * 1000).toISOString().slice(0, 10)
      : null),
  } : null;

  const deployedCount = models.filter(m => m.status === "DEPLOYED").length;
  const trainingCount = models.filter(m => m.status === "TRAINING").length + trainingJobs.length;
  const avgAccuracy = models.length > 0
    ? models.reduce((a, m) => a + (m.accuracy ?? 0), 0) / models.length
    : null;
  const lastDeploy = models.reduce((latest, m) => {
    const ts = m.deployed_at ?? m.last_deployed ?? m.updated_at;
    return ts && (!latest || new Date(ts) > new Date(latest)) ? ts : latest;
  }, null);

  /* sort models */
  const sortedModels = useMemo(() => {
    const list = [...models];
    list.sort((a, b) => {
      const va = a[sortCol] ?? 0;
      const vb = b[sortCol] ?? 0;
      return sortAsc ? (va > vb ? 1 : -1) : (va < vb ? 1 : -1);
    });
    return list;
  }, [models, sortCol, sortAsc]);

  /* feature importance chart */
  const sortedFeatures = [...features].sort((a, b) => Math.abs(b.importance ?? b.value ?? 0) - Math.abs(a.importance ?? a.value ?? 0));
  const maxImportance = sortedFeatures.length > 0 ? (Math.max(...sortedFeatures.map(f => Math.abs(f.importance ?? f.value ?? 0))) || 1) : 1;

  /* model comparison */
  const compareModels = selectedModels.length === 2
    ? selectedModels.map(name => models.find(m => (m.name ?? m.strategy) === name)).filter(Boolean)
    : [];

  const toggleModel = (name) => {
    setSelectedModels(prev =>
      prev.includes(name) ? prev.filter(n => n !== name) : prev.length < 2 ? [...prev, name] : [prev[1], name]
    );
  };

  const handleSort = (col) => {
    if (sortCol === col) setSortAsc(!sortAsc);
    else { setSortCol(col); setSortAsc(false); }
  };

  const sortIndicator = (col) => sortCol === col ? (sortAsc ? " \u25B2" : " \u25BC") : "";

  if (loading) {
    return (
      <>
        <div className="v2-pagehead">
          <div>
            <h1 className="v2-h1">ML Lab</h1>
            <div className="v2-muted">Loading model data...</div>
          </div>
        </div>
        <div className="v2-grid">
          {[1, 2, 3, 4].map(i => (
            <div key={i} className="v2-card">
              <div className="v2-ct">Loading...</div>
              <div className="v2-cv v2-blue" style={{ opacity: 0.3 }}>--</div>
            </div>
          ))}
        </div>
      </>
    );
  }

  return (
    <>
      <div className="v2-pagehead">
        <div>
          <h1 className="v2-h1">ML Lab</h1>
          <div className="v2-muted">Alpha generation, experiment tracking, model management.</div>
        </div>
        <div className="v2-row">
          <button className="v2-btn" onClick={() => toast("New experiment created", "info")}>New Experiment</button>
          <button className="v2-btn" onClick={() => toast("Retrain all queued", "info")}>Retrain All</button>
          <button className="v2-btn" onClick={() => toast("Results exported to CSV", "info")}>Export Results</button>
        </div>
      </div>

      {/* ── Top Stats ──────────────────────────────────── */}
      <div className="v2-grid" style={{ marginBottom: 16 }}>
        <Stat label="Active Models" value={deployedCount > 0 ? deployedCount : "--"} tone={deployedCount > 0 ? "green" : "blue"} sub={deployedCount > 0 ? `${models.length} total registered` : "No model data"} />
        <Stat label="Avg Accuracy" value={avgAccuracy != null ? fmtPct(avgAccuracy) : "--"} tone={avgAccuracy != null ? tonePct(avgAccuracy) : "blue"} sub={avgAccuracy != null ? "Across deployed models" : "No model data"} />
        <Stat label="Training Queue" value={trainingCount > 0 ? trainingCount : "--"} tone={trainingCount > 0 ? "amber" : "blue"} sub={trainingCount > 0 ? "Jobs in progress/queued" : "No jobs queued"} />
        <Stat label="Last Deploy" value={lastDeploy ? ago(lastDeploy) : "--"} tone={lastDeploy ? "green" : "blue"} sub={lastDeploy ? "Most recent deployment" : "No deployments"} />
      </div>

      <div className="v2-grid">
        {/* ── Model Registry Table ────────────────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Model Registry {selectedModels.length > 0 && <span className="v2-muted" style={{ fontSize: 11, marginLeft: 8 }}>{selectedModels.length}/2 selected for comparison</span>}</div>
          {sortedModels.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Models" message="ML models will appear here when experiment data is available from the API." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "30px 140px 90px 80px 80px 80px 90px 90px" }}>
                <span />
                <span style={{ cursor: "pointer" }} onClick={() => handleSort("name")}>Model{sortIndicator("name")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleSort("status")}>Status{sortIndicator("status")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleSort("accuracy")}>Accuracy{sortIndicator("accuracy")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleSort("precision")}>Precision{sortIndicator("precision")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleSort("sharpe")}>Sharpe{sortIndicator("sharpe")}</span>
                <span style={{ cursor: "pointer" }} onClick={() => handleSort("predictions")}>Predictions{sortIndicator("predictions")}</span>
                <span>Updated</span>
              </div>
              {sortedModels.map(m => {
                const name = m.name ?? m.strategy ?? m.model_name;
                const isSelected = selectedModels.includes(name);
                return (
                  <div key={name} className="v2-tr" style={{
                    gridTemplateColumns: "30px 140px 90px 80px 80px 80px 90px 90px",
                    background: isSelected ? "rgba(150,190,255,0.06)" : "transparent",
                    cursor: "pointer",
                  }} onClick={() => toggleModel(name)}>
                    <span>
                      <span style={{
                        display: "inline-block", width: 14, height: 14, borderRadius: 6,
                        border: `1px solid ${isSelected ? "var(--v2-blue)" : "rgba(255,255,255,0.15)"}`,
                        background: isSelected ? "rgba(150,190,255,0.25)" : "transparent",
                        textAlign: "center", fontSize: 10, lineHeight: "14px",
                      }}>
                        {isSelected ? "\u2713" : ""}
                      </span>
                    </span>
                    <span style={{ fontWeight: 600 }}>{name}</span>
                    <span className={statusColor(m.status)} style={{ fontWeight: 600, fontSize: 11, textTransform: "uppercase" }}>
                      {m.status ?? "UNKNOWN"}
                    </span>
                    <span className={`v2-mono v2-${tonePct(m.accuracy)}`}>{fmtPct(m.accuracy)}</span>
                    <span className={`v2-mono v2-${tonePct(m.precision)}`}>{fmtPct(m.precision)}</span>
                    <span className={`v2-mono v2-${m.sharpe > 1.5 ? "green" : m.sharpe > 0.5 ? "amber" : "red"}`}>
                      {m.sharpe != null ? m.sharpe.toFixed(2) : "--"}
                    </span>
                    <span className="v2-mono">{m.predictions ?? m.count ?? "--"}</span>
                    <span className="v2-mono v2-muted">{ago(m.updated_at ?? m.last_deployed)}</span>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Feature Importance Bar Chart ────────────── */}
        <div className="v2-card half">
          <div className="v2-ct">Feature Importance</div>
          {sortedFeatures.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Feature Data" message="Feature importance rankings will appear when a model is selected and evaluated." />
          ) : (
            <div style={{ marginTop: 12 }}>
              {sortedFeatures.slice(0, 10).map((f, i) => {
                const val = Math.abs(f.importance ?? f.value ?? 0);
                const pct = (val / maxImportance) * 100;
                return (
                  <div key={f.name ?? f.feature ?? i} style={{ marginBottom: 8 }}>
                    <div style={{ display: "flex", justifyContent: "space-between", fontSize: 11, marginBottom: 4 }}>
                      <span>{f.name ?? f.feature}</span>
                      <span className="v2-mono">{val.toFixed(3)}</span>
                    </div>
                    <div style={{ height: 6, borderRadius: 6, background: "rgba(255,255,255,0.06)" }}>
                      <div style={{
                        height: "100%", width: `${pct}%`, borderRadius: 6, transition: "width 0.4s ease",
                        background: i === 0 ? "var(--v2-green)" : i < 3 ? "var(--v2-blue)" : "rgba(150,190,255,0.4)",
                      }} />
                    </div>
                  </div>
                );
              })}
            </div>
          )}
        </div>

        {/* ── Model Comparison (2-model side-by-side) ── */}
        <div className="v2-card half">
          <div className="v2-ct">Model Comparison</div>
          {compareModels.length < 2 ? (
            <V2EmptyState icon={"\u29C6"} title={selectedModels.length === 0 ? "No Models Selected" : "Select 2 Models"} message="Select two models from the registry table to compare side-by-side." />
          ) : (
            <div style={{ marginTop: 12 }}>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16 }}>
                {compareModels.map((m, idx) => {
                  const name = m.name ?? m.strategy ?? m.model_name;
                  return (
                    <div key={name} style={{ padding: 12, borderRadius: 10, background: "rgba(255,255,255,0.03)", border: "1px solid rgba(255,255,255,0.06)" }}>
                      <div style={{ fontWeight: 700, fontSize: 13, marginBottom: 8, color: idx === 0 ? "var(--v2-blue)" : "var(--v2-green)" }}>{name}</div>
                      {[
                        { label: "Accuracy", value: fmtPct(m.accuracy) },
                        { label: "Precision", value: fmtPct(m.precision) },
                        { label: "Recall", value: fmtPct(m.recall) },
                        { label: "Sharpe", value: m.sharpe != null ? m.sharpe.toFixed(2) : "--" },
                        { label: "Status", value: m.status ?? "--" },
                      ].map(row => (
                        <div key={row.label} style={{ display: "flex", justifyContent: "space-between", padding: "3px 0", fontSize: 11, borderBottom: "1px solid rgba(255,255,255,0.04)" }}>
                          <span className="v2-muted">{row.label}</span>
                          <span className="v2-mono">{row.value}</span>
                        </div>
                      ))}
                    </div>
                  );
                })}
              </div>
              {/* delta row */}
              <div style={{ marginTop: 12, padding: "8px 10px", borderRadius: 10, background: "rgba(255,255,255,0.02)", border: "1px solid rgba(255,255,255,0.05)" }}>
                <div className="v2-muted" style={{ fontSize: 10, marginBottom: 4 }}>Delta (A - B)</div>
                <div style={{ display: "flex", gap: 16, flexWrap: "wrap" }}>
                  {["accuracy", "precision", "recall", "sharpe"].map(k => {
                    const diff = (compareModels[0][k] ?? 0) - (compareModels[1][k] ?? 0);
                    const isMetricPct = k !== "sharpe";
                    return (
                      <div key={k} style={{ fontSize: 11 }}>
                        <span className="v2-muted">{k}: </span>
                        <span className={`v2-mono v2-${diff > 0 ? "green" : diff < 0 ? "red" : "blue"}`}>
                          {diff > 0 ? "+" : ""}{isMetricPct ? fmtPct(diff) : diff.toFixed(2)}
                        </span>
                      </div>
                    );
                  })}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* ── Training Status Table ──────────────────── */}
        <div className="v2-card wide">
          <div className="v2-ct">Training Queue</div>
          {trainingJobs.length === 0 ? (
            <V2EmptyState icon={"\u29C6"} title="No Training Jobs" message="Active and queued training jobs will appear here." />
          ) : (
            <div className="v2-table" style={{ marginTop: 8 }}>
              <div className="v2-thead" style={{ gridTemplateColumns: "140px 100px 100px 100px 120px 1fr" }}>
                <span>Model</span>
                <span>Status</span>
                <span>Epoch</span>
                <span>Loss</span>
                <span>Started</span>
                <span>ETA</span>
              </div>
              {trainingJobs.map((j, i) => (
                <div key={j.model ?? j.name ?? i} className="v2-tr" style={{ gridTemplateColumns: "140px 100px 100px 100px 120px 1fr" }}>
                  <span style={{ fontWeight: 600 }}>{j.model ?? j.name}</span>
                  <span className={`v2-${j.status === "RUNNING" ? "green" : j.status === "QUEUED" ? "amber" : "blue"}`} style={{ fontWeight: 600, fontSize: 11, textTransform: "uppercase" }}>
                    {j.status ?? "QUEUED"}
                  </span>
                  <span className="v2-mono">{j.epoch != null ? `${j.epoch}/${j.total_epochs ?? "?"}` : "--"}</span>
                  <span className="v2-mono v2-muted">{j.loss != null ? j.loss.toFixed(4) : "--"}</span>
                  <span className="v2-mono v2-muted">{ago(j.started_at ?? j.created_at)}</span>
                  <span className="v2-mono v2-muted">{j.eta ?? "--"}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* ── Aura Alpha Strategy Catalogue Integration ──── */}
        <div className="v2-card wide">
          <div className="v2-ct">Aura Alpha Strategy Catalogue Integration</div>
          <div className="v2-row" style={{ gap: 20 }}>
            <div>
              <span className="v2-muted">Strategies loaded from API: </span>
              <span className="v2-mono v2-green" style={{ fontWeight: 700 }}>
                {strategyCount || "\u2014"}
              </span>
            </div>
            <div>
              <span className="v2-muted">Models covering strategies: </span>
              <span className="v2-mono v2-blue" style={{ fontWeight: 700 }}>{deployedCount || "\u2014"}</span>
            </div>
            <div>
              <span className="v2-muted">Coverage gap: </span>
              <span className="v2-mono v2-amber" style={{ fontWeight: 700 }}>
                {strategyCount > 0 && deployedCount > 0 ? Math.max(0, strategyCount - deployedCount) : "\u2014"}
              </span>
            </div>
          </div>
        </div>
      </div>
    </>
  );
}
